 74→//-----------------------------------------------------------------
 75→// Executes a link, attached to a trigger.
 76→// Toggles all walls linked to the switch.
 77→// Opens doors, Blasts blast walls, turns off illusions.
 78→void do_link(int8_t trigger_num)
 79→{
 80→	int i;
 81→
 82→	mprintf((0, "Door link!\n"));
 83→
 84→	if (trigger_num != -1) 
 85→	{
 86→		for (i=0;i<Triggers[trigger_num].num_links;i++) 
 87→		{
 88→			wall_toggle(&Segments[Triggers[trigger_num].seg[i]], Triggers[trigger_num].side[i]); 
 89→			mprintf((0," trigger_num %d : seg %d, side %d\n", 
 90→				trigger_num, Triggers[trigger_num].seg[i], Triggers[trigger_num].side[i]));
 91→  		}
 92→  	}
 93→}
