109→//turns lighting on.  returns true if lights were actually turned on. (they
110→//would not be if they had previously been shot out).
111→int do_light_on(int8_t trigger_num)
112→{
113→	int i,ret=0;
114→
115→	mprintf((0, "Lighting on!\n"));
116→
117→	if (trigger_num != -1) 
118→	{
119→		for (i=0;i<Triggers[trigger_num].num_links;i++) 
120→		{
121→			int segnum,sidenum;
122→			segnum = Triggers[trigger_num].seg[i];
123→			sidenum = Triggers[trigger_num].side[i];
124→
125→			//check if tmap2 casts light before turning the light on.  This
126→			//is to keep us from turning on blown-out lights
127→			if (TmapInfo[Segments[segnum].sides[sidenum].tmap_num2 & 0x3fff].lighting)
128→			{
129→				ret |= add_light(segnum, sidenum); 		//any light sets flag
130→				enable_flicker(segnum, sidenum);
131→			}
132→		}
133→	}
134→
135→	return ret;
136→}
