184→// Return trigger number if door is controlled by a wall switch, else return -1.
185→int door_is_wall_switched(int wall_num)
186→{
187→	int i, t;
188→
189→	for (t=0; t<Num_triggers; t++) 
190→	{
191→		for (i=0; i<Triggers[t].num_links; i++) 
192→		{
193→			if (Segments[Triggers[t].seg[i]].sides[Triggers[t].side[i]].wall_num == wall_num) {
194→				mprintf((0, "Wall #%i is keyed to trigger #%i, link #%i\n", wall_num, t, i));
195→				return t;
196→			}
197→	  	}
198→	}
199→
200→	return -1;
201→}
