231→// Changes walls pointed to by a trigger. returns true if any walls changed
232→int do_change_walls(int8_t trigger_num)
233→{
234→	int i,ret=0;
235→
236→	mprintf((0, "Wall remove!\n"));
237→
238→	if (trigger_num != -1) 
239→	{
240→		for (i=0;i<Triggers[trigger_num].num_links;i++) 
241→		{
242→			segment *segp,*csegp;
243→			short side,cside;
244→			int new_wall_type;
245→
246→			segp = &Segments[Triggers[trigger_num].seg[i]];
247→			side = Triggers[trigger_num].side[i];
248→
249→			csegp = &Segments[segp->children[side]];
250→			cside = find_connect_side(segp, csegp);
251→			Assert(cside != -1);
252→
253→			//segp->sides[side].wall_num = -1;
254→			//csegp->sides[cside].wall_num = -1;
255→
256→			switch (Triggers[trigger_num].type)
257→			{
258→				case TT_OPEN_WALL:		new_wall_type = WALL_OPEN; break;
259→				case TT_CLOSE_WALL:		new_wall_type = WALL_CLOSED; break;
260→				case TT_ILLUSORY_WALL:	new_wall_type = WALL_ILLUSION; break;
261→			}
262→
263→			if (Walls[segp->sides[side].wall_num].type == new_wall_type && Walls[csegp->sides[cside].wall_num].type == new_wall_type)
264→				continue;		//already in correct state, so skip
265→
266→			ret = 1;
267→
268→			switch (Triggers[trigger_num].type) 
269→			{
270→	
271→				case TT_OPEN_WALL:
272→					mprintf((0,"Open wall\n"));
273→
274→					if ((TmapInfo[segp->sides[side].tmap_num].flags & TMI_FORCE_FIELD)) 
275→					{
276→						vms_vector pos;
277→						compute_center_point_on_side(&pos, segp, side );
278→						digi_link_sound_to_pos( SOUND_FORCEFIELD_OFF, segp-Segments, side, &pos, 0, F1_0 );
279→						Walls[segp->sides[side].wall_num].type = new_wall_type;
280→						Walls[csegp->sides[cside].wall_num].type = new_wall_type;
281→						digi_kill_sound_linked_to_segment(segp-Segments,side,SOUND_FORCEFIELD_HUM);
282→						digi_kill_sound_linked_to_segment(csegp-Segments,cside,SOUND_FORCEFIELD_HUM);
283→					}
284→					else
285→						start_wall_cloak(segp,side);
286→
287→					ret = 1;
288→
289→					break;
290→
291→				case TT_CLOSE_WALL:
292→					mprintf((0,"Close wall\n"));
293→
294→					if ((TmapInfo[segp->sides[side].tmap_num].flags & TMI_FORCE_FIELD)) 
295→					{
296→						vms_vector pos;
297→						compute_center_point_on_side(&pos, segp, side );
298→						digi_link_sound_to_pos(SOUND_FORCEFIELD_HUM,segp-Segments,side,&pos,1, F1_0/2);
299→						Walls[segp->sides[side].wall_num].type = new_wall_type;
300→						Walls[csegp->sides[cside].wall_num].type = new_wall_type;
301→					}
302→					else
303→						start_wall_decloak(segp,side);
304→					break;
305→
306→				case TT_ILLUSORY_WALL:
307→					mprintf((0,"Illusory wall\n"));
308→					Walls[segp->sides[side].wall_num].type = new_wall_type;
309→					Walls[csegp->sides[cside].wall_num].type = new_wall_type;
310→					break;
311→			}
312→
313→
314→			kill_stuck_objects(segp->sides[side].wall_num);
315→			kill_stuck_objects(csegp->sides[cside].wall_num);
316→
317→  		}
318→  	}
319→
320→	return ret;
321→}
