402→int wall_is_forcefield(trigger *trig)
403→{
404→	int i;
405→
406→	for (i=0;i<trig->num_links;i++)
407→		if ((TmapInfo[Segments[trig->seg[i]].sides[trig->side[i]].tmap_num].flags & TMI_FORCE_FIELD))
408→			break;
409→
410→	return (i<trig->num_links);
411→}
