413→int check_trigger_sub(int trigger_num, int pnum,int shot)
414→{
415→	trigger *trig = &Triggers[trigger_num];
416→
417→	mprintf ((0,"trignum=%d type=%d shot=%d\n",trigger_num,trig->type,shot));
418→
419→	if (trig->flags & TF_DISABLED)
420→		return 1;		//1 means don't send trigger hit to other players
421→
422→	if (trig->flags & TF_ONE_SHOT)		//if this is a one-shot...
423→		trig->flags |= TF_DISABLED;		//..then don't let it happen again
424→
425→	switch (trig->type) 
426→	{
427→		case TT_EXIT:
428→
429→			if (pnum!=Player_num)
430→			  break;
431→
432→			digi_stop_all();		//kill the sounds
433→			
434→			if (Current_level_num > 0) 
435→			{
436→				start_endlevel_sequence();
437→				mprintf((0,"WOOHOO! (leaving the mine!)\n"));
438→			} else if (Current_level_num < 0) {
439→				if ((Players[Player_num].shields < 0) || Player_is_dead)
440→					break;
441→
442→				ExitSecretLevel();
443→				return 1;
444→			} 
445→			else 
446→			{
447→				#ifdef EDITOR
448→					nm_messagebox( "Yo!", 1, "You have hit the exit trigger!", "" );
449→				#else
450→					Int3();		//level num == 0, but no editor!
451→				#endif
452→			}
453→			return 1;
454→			break;
455→
456→		case TT_SECRET_EXIT: 
457→		{
458→			int	truth;
459→
460→			if (CurrentDataVersion == DataVer::DEMO)
461→			{
462→				HUD_init_message("Secret Level Teleporter disabled in Descent 2 Demo");
463→				digi_play_sample(SOUND_BAD_SELECTION, F1_0);
464→				break;
465→			}
466→ 
467→			if (pnum!=Player_num)
468→				break;
469→
470→			if ((Players[Player_num].shields < 0) || Player_is_dead)
471→				break;
472→
473→			if (Game_mode & GM_MULTI) 
474→			{
475→				HUD_init_message("Secret Level Teleporter disabled in multiplayer!");
476→				digi_play_sample( SOUND_BAD_SELECTION, F1_0 );
477→				break;
478→			}
479→
480→			truth = p_secret_level_destroyed();
481→
482→			if (Newdemo_state == ND_STATE_RECORDING)			// record whether we're really going to the secret level
483→				newdemo_record_secret_exit_blown(truth);
484→
485→			if ((Newdemo_state != ND_STATE_PLAYBACK) && truth)
486→			{
487→				HUD_init_message("Secret Level destroyed.  Exit disabled.");
488→				digi_play_sample(SOUND_BAD_SELECTION, F1_0);
489→				break;
490→			}
491→
492→			if (Newdemo_state == ND_STATE_RECORDING)		// stop demo recording
493→				Newdemo_state = ND_STATE_PAUSED;
494→
495→			digi_stop_all();		//kill the sounds
496→
497→			digi_play_sample(SOUND_SECRET_EXIT, F1_0);
498→			mprintf((0, "Exiting to secret level\n"));
499→
500→			gr_palette_fade_out(gr_palette, 32, 0);
501→			EnterSecretLevel();
502→			Control_center_destroyed = 0;
503→			return 1;
504→			break;
505→
506→		}
507→
508→		case TT_OPEN_DOOR:
509→			mprintf((0,"D"));
510→			do_link(trigger_num);
511→			print_trigger_message (pnum,trigger_num,shot,"Door%s opened!");
512→			
513→			break;
514→
515→		case TT_CLOSE_DOOR:
516→			do_close_door(trigger_num);
517→			print_trigger_message (pnum,trigger_num,shot,"Door%s closed!");
518→			break;
519→
520→		case TT_UNLOCK_DOOR:
521→			mprintf((0,"D"));
522→			do_unlock_doors(trigger_num);
523→			print_trigger_message (pnum,trigger_num,shot,"Door%s unlocked!");
524→			
525→			break;
526→	
527→		case TT_LOCK_DOOR:
528→			mprintf((0,"D"));
529→			do_lock_doors(trigger_num);
530→			print_trigger_message (pnum,trigger_num,shot,"Door%s locked!");
531→
532→			break;
533→	
534→		case TT_OPEN_WALL:
535→			if (do_change_walls(trigger_num))
536→				if (wall_is_forcefield(trig))
537→					print_trigger_message (pnum,trigger_num,shot,"Force field%s deactivated!");
538→				else
539→					print_trigger_message (pnum,trigger_num,shot,"Wall%s opened!");
540→			break;
541→
542→		case TT_CLOSE_WALL:
543→			if (do_change_walls(trigger_num))
544→				if (wall_is_forcefield(trig))
545→					print_trigger_message (pnum,trigger_num,shot,"Force field%s activated!");
546→				else
547→					print_trigger_message (pnum,trigger_num,shot,"Wall%s closed!");
548→			break;
549→
550→		case TT_ILLUSORY_WALL:
551→			//don't know what to say, so say nothing
552→			do_change_walls(trigger_num);
553→			break;
554→
555→		case TT_MATCEN:
556→			if (!(Game_mode & GM_MULTI) || (Game_mode & GM_MULTI_ROBOTS))
557→				do_matcen(trigger_num);
558→			break;
559→	
560→		case TT_ILLUSION_ON:
561→			mprintf((0,"I"));
562→			do_il_on(trigger_num);
563→			print_trigger_message (pnum,trigger_num,shot,"Illusion%s on!");
564→			break;
565→	
566→		case TT_ILLUSION_OFF:
567→			mprintf((0,"i"));
568→			do_il_off(trigger_num);
569→			print_trigger_message (pnum,trigger_num,shot,"Illusion%s off!");
570→			break;
571→
572→		case TT_LIGHT_OFF:
573→			if (do_light_off(trigger_num))
574→				print_trigger_message (pnum,trigger_num,shot,"Lights off!");
575→			break;
576→
577→		case TT_LIGHT_ON:
578→			if (do_light_on(trigger_num))
579→				print_trigger_message (pnum,trigger_num,shot,"Lights on!");
580→
581→			break;
582→
583→		default:
584→			Int3();
585→			break;
586→	}
587→
588→	return 0;
589→}
