591→//-----------------------------------------------------------------
592→// Checks for a trigger whenever an object hits a trigger side.
593→void check_trigger(segment *seg, short side, short objnum,int shot)
594→{
595→	int wall_num, trigger_num;	//, ctrigger_num;
596→	//segment *csegp;
597→ 	//short cside;
598→
599→//	mprintf(0,"T");
600→
601→	if ((objnum == Players[Player_num].objnum) || ((Objects[objnum].type == OBJ_ROBOT) && (Robot_info[Objects[objnum].id].companion)))
602→	{
603→
604→		if ( Newdemo_state == ND_STATE_RECORDING )
605→			newdemo_record_trigger( seg-Segments, side, objnum,shot);
606→
607→		wall_num = seg->sides[side].wall_num;
608→		if ( wall_num == -1 ) return;
609→		
610→		trigger_num = Walls[wall_num].trigger;
611→
