144→int check_trigger_sub(int trigger_num, int pnum)
145→{
146→	if (pnum == Player_num) 
147→	{
148→		if (Triggers[trigger_num].flags & TRIGGER_SHIELD_DAMAGE) 
149→		{
150→			Players[Player_num].shields -= Triggers[trigger_num].value;
151→			mprintf((0, "BZZT!\n"));
152→		}
153→
154→		if (Triggers[trigger_num].flags & TRIGGER_EXIT) 
155→		{
156→			start_endlevel_sequence();
157→			mprintf((0, "WOOHOO! (leaving the mine!)\n"));
158→		}
159→
160→		if (Triggers[trigger_num].flags & TRIGGER_SECRET_EXIT) 
161→		{
162→			if (Newdemo_state == ND_STATE_RECORDING)		// stop demo recording
163→				Newdemo_state = ND_STATE_PAUSED;
164→
165→			Fuelcen_control_center_destroyed = 0;
166→			mprintf((0, "Exiting to secret level\n"));
167→#ifdef NETWORK
168→			if (Game_mode & GM_MULTI)
169→				multi_send_endlevel_start(1);
170→#endif
171→#ifdef NETWORK
172→			if (Game_mode & GM_NETWORK)
173→				network_do_frame(1, 1);
174→#endif
175→			gr_palette_fade_out(gr_palette, 32, 0);
176→			PlayerFinishedLevel(1);		//1 means go to secret level
177→			return 1;
178→		}
179→
180→		if (Triggers[trigger_num].flags & TRIGGER_ENERGY_DRAIN) 
181→		{
182→			Players[Player_num].energy -= Triggers[trigger_num].value;
183→			mprintf((0, "SLURP!\n"));
184→		}
185→	}
186→
187→	if (Triggers[trigger_num].flags & TRIGGER_CONTROL_DOORS) 
188→	{
189→		mprintf((0, "D"));
190→		do_link(trigger_num);
191→	}
192→
193→	if (Triggers[trigger_num].flags & TRIGGER_MATCEN) 
194→	{
195→		if (!(Game_mode & GM_MULTI) || (Game_mode & GM_MULTI_ROBOTS))
196→			do_matcen(trigger_num);
197→	}
198→
199→	if (Triggers[trigger_num].flags & TRIGGER_ILLUSION_ON) 
200→	{
201→		mprintf((0, "I"));
202→		do_il_on(trigger_num);
203→	}
204→
205→	if (Triggers[trigger_num].flags & TRIGGER_ILLUSION_OFF) 
206→	{
207→		//		Triggers[trigger_num].time = TRIGGER_DELAY_DOOR;
208→		mprintf((0, "i"));
209→		do_il_off(trigger_num);
210→	}
211→	return 0;
212→}
