215→// Checks for a trigger whenever an object hits a trigger side.
216→void check_trigger(segment* seg, short side, short objnum)
217→{
218→	int wall_num, trigger_num, ctrigger_num;
219→	segment* csegp;
220→	short cside;
221→
222→	//	mprintf(0,"T");
223→
224→	if (objnum == Players[Player_num].objnum) 
225→	{
226→
227→		//		if ( Newdemo_state == ND_STATE_RECORDING )
228→		//			newdemo_record_trigger( seg-Segments, side, objnum );
229→
230→		if (Newdemo_state == ND_STATE_PLAYBACK)
231→			return;
232→
233→		wall_num = seg->sides[side].wall_num;
234→		if (wall_num == -1) return;
235→
236→		trigger_num = Walls[wall_num].trigger;
237→
238→		if (trigger_num == -1)
239→			return;
240→
241→		if (check_trigger_sub(trigger_num, Player_num))
242→			return;
243→
244→		if (Triggers[trigger_num].flags & TRIGGER_ONE_SHOT) 
245→		{
246→			Triggers[trigger_num].flags &= ~TRIGGER_ON;
247→
248→			csegp = &Segments[seg->children[side]];
249→			cside = find_connect_side(seg, csegp);
250→			Assert(cside != -1);
251→
252→			wall_num = csegp->sides[cside].wall_num;
253→			if (wall_num == -1) return;
254→
255→			ctrigger_num = Walls[wall_num].trigger;
256→
257→			Triggers[ctrigger_num].flags &= ~TRIGGER_ON;
258→		}
259→#ifndef SHAREWARE
260→#ifdef NETWORK
261→		if (Game_mode & GM_MULTI)
262→			multi_send_trigger(trigger_num);
263→#endif
264→#endif
265→	}
266→}
